import '@/styles/globals.css';

import { Close } from '@mui/icons-material';
import { CssBaseline, IconButton, ThemeProvider } from '@mui/material';
import { AppCacheProvider } from '@mui/material-nextjs/v14-pagesRouter';
import { LocalizationProvider } from '@mui/x-date-pickers';
import { AdapterMoment } from '@mui/x-date-pickers/AdapterMoment';
import { Amplify } from 'aws-amplify';
import _ from 'lodash';
import moment from 'moment';
import { NextPage } from 'next';
import { AppProps } from 'next/app';
import {
  closeSnackbar,
  SnackbarProvider as NotistackSnackbarProvider,
} from 'notistack';
import { ReactElement, ReactNode, useCallback, useEffect } from 'react';
import { DndProvider } from 'react-dnd';
import { HTML5Backend } from 'react-dnd-html5-backend';
import { Provider } from 'react-redux';

import { EnvManager } from '@/constants/env.constants';
import useServicesHook from '@/hooks';
import RootLayout from '@/layouts/root.layout';
import { User } from '@/models/user';
import { store, useDispatch } from '@/store';
import { actions as masterDataActions } from '@/store/slices/master.slice';
import { actions as userDataActions } from '@/store/slices/user.slice';
import { theme } from '@/theme';
import {
  getDefaultLanguage,
  getDefaultUnit,
  initializeI18nSettings,
} from '@/utils/i18n';
import { logger } from '@/utils/logger';

export type NextPageWithLayout<P = {}, IP = P> = NextPage<P, IP> & {
  getLayout?: (page: ReactElement, pageProps: any) => ReactNode;
};

type AppPropsWithLayout = AppProps & {
  Component: NextPageWithLayout;
};

function AppInner({ Component, pageProps }: AppPropsWithLayout) {
  const dispatch = useDispatch();
  const { router, services } = useServicesHook();

  const getLayout = Component.getLayout ?? ((page) => page);

  const processMastersData = async () => {
    const pitchTypesResult = await services.default.master.getPitchTypes();

    if (!pitchTypesResult.error) {
      dispatch(masterDataActions.setPitchTypes(pitchTypesResult.pitchTypes));
    }
  };

  /**
   * 初期化処理
   * - 認証情報を確認する
   * - 詳細なユーザ情報の取得
   * - ユーザ情報及びログインステータスのグローバルstoreへの格納（全ページ的に利用するため）
   */
  const init = useCallback(async () => {
    // Cognito: 初期化
    Amplify.configure({
      Auth: {
        Cognito: {
          ...(['local', 'test'].includes(EnvManager.config.APP_ENV)
            ? {
                userPoolEndpoint: EnvManager.config.COGNITO_ENDPOINT ?? '',
              }
            : {}),
          userPoolId: EnvManager.config.COGNITO_POOL_ID,
          userPoolClientId: EnvManager.config.COGNITO_POOL_CLIENT_ID,
        },
      },
    });

    const defaultLanguage = getDefaultLanguage();
    // 認証済みかの確認
    if (!(await services.default.auth.hasApiCredentials())) {
      // loginStatus == 'no' (未認証)
      dispatch(
        userDataActions.setUserWithLoginStatus({ user: null, error: null }),
      );
      logger.warn('*** no creds ***');
      const lang = services.localStorage.getLanguage(null) ?? defaultLanguage;
      logger.debug(`Lang: ${lang}`);
      initializeI18nSettings(lang);
      return;
    }
    dispatch(masterDataActions.setDeploymentCheckedDate(new Date()));
    dispatch(
      masterDataActions.setMaintenanceCheckedDate(
        moment(new Date()).subtract(1, 'year').toDate(),
      ),
    );

    processMastersData();

    // ユーザ情報の取得
    const { user, error } = await services.default.user.getMe();
    if (error || !user?.profile) {
      dispatch(
        userDataActions.setUserWithLoginStatus({ user: null, error: null }),
      );
      initializeI18nSettings(defaultLanguage);
      return;
    }
    let accessibleTeams = user.teams;
    // superuser
    if (User.isAccessible(user, 'all', 'admin', 'read', false)) {
      const { teams, error } = await services.default.superAdmin.getTeams({ statusFilter: 'active' });
      if (teams) {
        accessibleTeams = teams;
      }
    }
    const lang =
      services.localStorage.getLanguage(user?.id ?? null) ?? defaultLanguage;
    const unit =
      services.localStorage.getUnit(user?.id ?? null) ?? getDefaultUnit();
    dispatch(userDataActions.setUnit({ unit }));
    logger.debug(`Lang: ${lang}`);
    initializeI18nSettings(lang);

    // 取得したユーザ情報のセット
    // loginStatus == 'yes'(成功) or 'error'（サーバエラー）
    dispatch(userDataActions.setUserWithLoginStatus({ user, error: error }));

    dispatch(
      userDataActions.setTeams({
        teamIdToUserRoles: user.givenUserRoles,
        teams: accessibleTeams,
        teamId: services.localStorage.getCurrentTeamId(user.id),
        isSuperAdminMode: User.isAccessible(
          user,
          'all',
          'admin',
          'read',
          false,
        ),
      }),
    );
  }, [services.default.user, dispatch]);

  useEffect(() => {
    logger.debug(`[App] Initializing...`);
    init();
  }, [init]);

  return (
    <RootLayout>
      {getLayout(<Component {...pageProps} />, pageProps)}
    </RootLayout>
  );
}

function SnackbarProvider({ children }: { children: ReactNode }) {
  return (
    <NotistackSnackbarProvider
      autoHideDuration={3000}
      maxSnack={1}
      anchorOrigin={{ horizontal: 'center', vertical: 'bottom' }}
      action={(snackbarId) => (
        <IconButton
          onClick={() => closeSnackbar(snackbarId)}
          sx={{ color: '#fff' }}
        >
          <Close />
        </IconButton>
      )}
    >
      {children}
    </NotistackSnackbarProvider>
  );
}

export default function MyApp(props: AppProps) {
  return (
    <Provider store={store}>
      <AppCacheProvider {...props}>
        <ThemeProvider theme={theme}>
          <CssBaseline />
          <DndProvider backend={HTML5Backend}>
            <LocalizationProvider dateAdapter={AdapterMoment}>
              <SnackbarProvider>
                <AppInner {...props} />
              </SnackbarProvider>
            </LocalizationProvider>
          </DndProvider>
        </ThemeProvider>
      </AppCacheProvider>
    </Provider>
  );
}
